INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c7f30da7-b4b8-4fd3-852e-b6ee7681f8c3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vault - KMS, Customer-Managed Keys, and Envelope Encryption$escape$,
  $escape$Vault supports two types of encryption: symmetric and asymmetric. Symmetric encryption uses a single key, while asymmetric encryption uses a key pair. Vault's KMS (Key Management Service) allows you to store and manage encryption keys. Customer-managed keys are stored and managed outside of Vault. Envelope encryption combines symmetric encryption for performance and asymmetric encryption for key management. Use `vault write secret/secret/` to create a new secret and `vault kv put` to store encrypted data. Use `vault read` to retrieve encrypted data.$escape$,
  NULL,
  NULL,
