INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7388a1ab-6e78-4f8e-b45f-7251a22fc1c5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vault Incident Response: Containing Blast Radius with Isolation Playbooks$escape$,
  $escape$When an incident occurs in Vault, isolating the affected system and containing the blast radius are crucial steps in incident response. Vault provides a built-in feature called Isolation Playbooks, which allows you to automate this process. To create an Isolation Playbook, use the `vault write` command with the `path` parameter set to `sys/iso/playbook`. For example:

```bash
vault write sys/iso/playbook \
  name=my-playbook \
  command=\"vault lease revoke -prefix=my-namespace\\"$escape$,
  $escape$null$escape$,
  $escape$bash$escape$,
