INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '42095a7e-2ff1-424e-bf8d-97853d7b758d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vault Integrates with Falco for Runtime Security$escape$,
  $escape$Vault's Secret Engine integrates with Falco, an open-source runtime security project, to provide runtime security for containers. To enable Falco integration, configure the Falco Secret Engine in your Vault instance using the `vault secrets enable falco` command. Once enabled, Vault provides Falco with the necessary secrets and configuration to detect and prevent security threats in your containers. Use the `vault read falco/config` command to retrieve the Falco configuration.$escape$,
  $escape$vault secrets enable falco
vault write falco/config --config='{"output": "stdout"}'$escape$,
  $escape$bash$escape$,
