INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '86c573fc-6651-42c2-9b38-d2b04f799054',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vault Secrets Rotation — Automated, Zero-Downtime, and Audit Trails$escape$,
  $escape$Vault supports automated secrets rotation using the `update` method. To rotate a secret, update its version with the `update` API: `vault write /path/to/secret/rotate version=2`. For zero-downtime rotation, use the `lease_id` parameter: `vault write /path/to/secret/rotate lease_id=<lease_id>`. Vault provides an audit trail for all rotation operations, storing them in the `audit_log` backend. To access the audit trail, query the `audit_log` API: `vault read /sys/audit-log`. Use the `limit` parameter to retrieve a specific number of entries: `vault read /sys/audit-log?limit=10`.$escape$,
  NULL,
  NULL,
