INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd51068a4-35cc-426b-b79f-fffe502ea2d4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vault - Mastering Secret Engines and Dynamic Secrets$escape$,
  $escape$Vault uses secret engines to manage secrets, which can be AWS, Kubernetes, or generic. Dynamic secrets are generated on-the-fly by a secret engine, reducing the risk of secret exposure. Lease TTL (time-to-live) determines how long a secret is valid. For example, setting a low TTL for database credentials ensures they expire frequently. Auth methods authenticate users before they can access Vault. You can use the `auth-userpass` method to authenticate users with a username and password.$escape$,
  $escape$
   // Enable the AWS secret engine
   vault secrets enable aws

   // Generate a dynamic secret for AWS IAM
   vault write aws/creds/my-role
   $escape$,
  $escape$bash$escape$,
